7		const PROVIDER_STATUSES_QUERY = gql`
8			query ProviderStatuses {
9				providerStatuses {
10					name
11					kind
12					providerType
13					baseURL
14					model
15					status
16					reachable
17					detail
18					modelCount
19					isDefault
20					cooldownUntil
21					lastCheckedAt
22					defaultForProfile
23					usage {
24						tokensUsedLastHour
25						tokensUsedLast24h
26						requestsLastHour
27						requestsLast24h
28					}
29					quota {
30						ceilingTokens
31						ceilingWindowSeconds
32						remaining
33						resetAt
34					}
35					sparkline
36				}
37				harnessStatuses {
38					name
39					kind
40					providerType
41					baseURL
42					model
43					status
44					reachable
45					detail
46					modelCount
47					isDefault
48					cooldownUntil
49					lastCheckedAt
50					defaultForProfile
51					usage {
52						tokensUsedLastHour
53						tokensUsedLast24h
54						requestsLastHour
55						requestsLast24h
56					}
57					quota {
58						ceilingTokens
59						ceilingWindowSeconds
60						remaining
61						resetAt
62					}
63					sparkline
64				}
65			}
66		`;
67	
68		const PROVIDER_MODELS_QUERY = gql`
69			query ProviderModels($name: String!, $kind: ProviderKind!) {
70				providerModels(name: $name, kind: $kind) {
71					name
72					kind
73					baseURL
74					fetchedAt
75					fromCache
76					models {
77						id
78						contextLength
79						available
80					}
81				}
82			}
83		`;
84	
85		const REFRESH_PROVIDER_MODELS_MUTATION = gql`
86			mutation RefreshProviderModels($name: String!, $kind: ProviderKind!) {
87				refreshProviderModels(name: $name, kind: $kind) {
88					name
89					kind
90					baseURL
91					fetchedAt
92					fromCache
93					models {
94						id
95						contextLength
96						available
97					}
98				}
99			}
100		`;
101	
102		const DEFAULT_ROUTE_QUERY = gql`
103			query DefaultRouteStatus {
104				defaultRouteStatus {
105					modelRef
106					resolvedProvider
107					resolvedModel
108					strategy
109				}
110			}
111		`;
112	
113		interface ProviderUsage {
114			tokensUsedLastHour: number | null;
115			tokensUsedLast24h: number | null;
116			requestsLastHour: number | null;
117			requestsLast24h: number | null;
118		}
119	
120		interface ProviderQuota {
121			ceilingTokens: number | null;
122			ceilingWindowSeconds: number | null;
123			remaining: number | null;
124			resetAt: string | null;
125		}
126	
127		interface ProviderStatus {
128			name: string;
129			kind: 'ENDPOINT' | 'HARNESS';
130			providerType: string;
131			baseURL: string;
132			model: string;
133			status: string;
134			reachable: boolean;
135			detail: string;
136			modelCount: number;
137			isDefault: boolean;
138			cooldownUntil: string | null;
139			lastCheckedAt: string | null;
140			defaultForProfile: string[];
141			usage: ProviderUsage | null;
142			quota: ProviderQuota | null;
143			sparkline: number[];
144		}
145	
146		interface ProviderModelEntry {
147			id: string;
148			contextLength: number | null;
149			available: boolean;
150		}
151	
152		interface ProviderModelsResult {
153			name: string;
154			kind: 'ENDPOINT' | 'HARNESS';
155			baseURL: string;
156			fetchedAt: string;
157			fromCache: boolean;
158			models: ProviderModelEntry[];
159		}
160	
161		interface DefaultRouteStatus {
162			modelRef: string;
163			resolvedProvider: string | null;
164			resolvedModel: string | null;
165			strategy: string | null;
166		}
167	
168		// First-paint state: we render the table from the query result as soon as
169		// it lands. The query itself returns cached probe results — a live refresh
170		// action will enqueue fresh probes in a future iteration.
171		let rows = $state<ProviderStatus[]>([]);
172		let defaultRoute = $state<DefaultRouteStatus | null>(null);
173		let loading = $state(true);
174		let error = $state<string | null>(null);
175		let firstPaintAt = $state<number | null>(null);
176	
177		// Per-row model snapshots loaded on demand when a row is expanded.
178		const modelsByKey = $state<Record<string, ProviderModelsResult>>({});
179		const modelsLoading = $state<Record<string, boolean>>({});
180		const modelsError = $state<Record<string, string>>({});
181		const expanded = $state<Record<string, boolean>>({});
182	
183		// Threshold above which the inline list is truncated and a drilldown
184		// link to the per-provider detail page is shown.
185		const MODEL_LIST_INLINE_LIMIT = 10;
186	
187		function rowKey(row: ProviderStatus): string {
188			return row.kind + '|' + row.name;
189		}
190	
191		let modelsClient: ReturnType<typeof createClient> | null = null;
192	
193		async function loadModels(row: ProviderStatus): Promise<void> {
194			const key = rowKey(row);
195			if (!modelsClient) modelsClient = createClient();
196			modelsLoading[key] = true;
197			delete modelsError[key];
198			try {
199				const res = await modelsClient.request<{
200					providerModels: ProviderModelsResult | null;
201				}>(PROVIDER_MODELS_QUERY, { name: row.name, kind: row.kind });
202				if (res.providerModels) modelsByKey[key] = res.providerModels;
203			} catch (e) {
204				modelsError[key] = e instanceof Error ? e.message : String(e);
205			} finally {
206				modelsLoading[key] = false;
207			}
208		}
209	
210		async function refreshModels(row: ProviderStatus): Promise<void> {
211			const key = rowKey(row);
212			if (!modelsClient) modelsClient = createClient();
213			modelsLoading[key] = true;
214			delete modelsError[key];
215			try {
216				const res = await modelsClient.request<{
217					refreshProviderModels: ProviderModelsResult;
218				}>(REFRESH_PROVIDER_MODELS_MUTATION, { name: row.name, kind: row.kind });
219				modelsByKey[key] = res.refreshProviderModels;
220				expanded[key] = true;
221			} catch (e) {
222				modelsError[key] = e instanceof Error ? e.message : String(e);
223			} finally {
224				modelsLoading[key] = false;
225			}
226		}
227	
228		function toggleExpanded(row: ProviderStatus): void {
229			const key = rowKey(row);
230			const next = !expanded[key];
231			expanded[key] = next;
232			if (next && !modelsByKey[key] && !modelsLoading[key]) {
233				void loadModels(row);
234			}
235		}
236	
237		$effect(() => {
238			if (!loading && firstPaintAt === null) {
239				firstPaintAt = Date.now();
240			}
241		});
242	
243		// Polling interval for live row patching after first paint. Chosen to be
244		// short enough that probe results surface within the 5s AC budget but long
245		// enough to not hammer the server. AC 1: rows patch within 5s of probe
246		// completion — since the resolver returns cached rows updated asynchronously
247		// by refreshProviderStatuses, polling here is sufficient to reflect them.
248		const POLL_INTERVAL_MS = 2500;
249		let pollTimer: ReturnType<typeof setInterval> | null = null;
250	
251		async function refresh(client: ReturnType<typeof createClient>) {
252			const result = await client.request<{
253				providerStatuses: ProviderStatus[];
254				harnessStatuses: ProviderStatus[];
255			}>(PROVIDER_STATUSES_QUERY);
256			rows = [...(result.providerStatuses ?? []), ...(result.harnessStatuses ?? [])];
257		}
258	
259		onMount(() => {
260			const client = createClient();
261			// First paint: provider + harness rows. defaultRouteStatus fires in
262			// parallel via a separate query so a slow route-resolver can't delay
263			// the table from rendering. AC 1: table interactive within 500ms.
264			refresh(client)
265				.catch((e) => {
266					error = e instanceof Error ? e.message : String(e);
267				})
268				.finally(() => {
269					loading = false;
270				});
271	
272			client
273				.request<{ defaultRouteStatus: DefaultRouteStatus | null }>(DEFAULT_ROUTE_QUERY)
274				.then((res) => {
275					defaultRoute = res.defaultRouteStatus ?? null;
276				})
277				.catch(() => {
278					// Non-fatal: the default-route widget is informational only.
279				});
280	
281			pollTimer = setInterval(() => {
282				refresh(client).catch(() => {
283					// Polling errors are transient; keep the last-known rows.
284				});
285			}, POLL_INTERVAL_MS);
286	
287			return () => {
288				if (pollTimer != null) {
289					clearInterval(pollTimer);
290					pollTimer = null;
291				}
292			};
293		});
294	
295		function statusClass(row: ProviderStatus): string {
296			if (row.reachable) return 'text-status-closed';
297			const lower = row.status.toLowerCase();
298			if (
299				lower.includes('connected') ||
300				lower === 'available' ||
301				lower.includes('api key configured')
302			) {
303				return 'text-status-closed';
304			}
305			if (
306				lower.includes('cooldown') ||
307				lower.includes('unreachable') ||
308				lower.includes('error') ||
309				lower === 'unavailable' ||
310				lower.startsWith('unavailable')
311			) {
312				return 'text-status-failed';
313			}
314			return 'text-status-in-progress';
315		}
316	
317		function formatTokens(n: number | null | undefined): string {
318			if (n == null) return '—';
319			if (n < 1000) return `${n}`;
320			if (n < 1_000_000) return `${(n / 1000).toFixed(1)}k`;
321			return `${(n / 1_000_000).toFixed(2)}M`;
322		}
323	
324		function utilizationPct(usage: ProviderUsage | null, quota: ProviderQuota | null): number | null {
325			if (!usage || !quota) return null;
326			if (quota.ceilingTokens == null || quota.ceilingTokens <= 0) return null;
327			const window = quota.ceilingWindowSeconds ?? 60;
328			// Choose the usage field that matches the ceiling window (1h / 24h).
329			const usedTokens = window <= 3600 ? usage.tokensUsedLastHour : usage.tokensUsedLast24h;
330			if (usedTokens == null) return null;
331			return Math.min(100, Math.round((usedTokens * 100) / quota.ceilingTokens));
332		}
333	
334		function sparklineMax(values: number[]): number {
335			let m = 0;
336			for (const v of values) if (v > m) m = v;
337			return m === 0 ? 1 : m;
338		}
339	
340		function sparkBarHeight(value: number, max: number): string {
341			const pct = Math.round((value * 100) / max);
342			return `${Math.max(2, pct)}%`;
343		}
344	
345		function detailHref(row: ProviderStatus): string {
346			const nodeId = $page.params.nodeId;
347			return `/nodes/${nodeId}/providers/${encodeURIComponent(row.name)}`;
348		}
