		reachable: true,
		detail: 'api key configured',
		modelCount: 4,
		isDefault: true,
		cooldownUntil: null,
		lastCheckedAt: '2026-05-03T12:00:00Z',
		defaultForProfile: ['default'],
		usage: { tokensUsedLastHour: 0, tokensUsedLast24h: 0, requestsLastHour: 0, requestsLast24h: 0 },
		quota: null,
		sparkline: []
	},
	{
		name: 'codex',
		kind: 'HARNESS',
		providerType: 'openai',
		baseURL: '(api)',
		model: 'gpt-5',
		status: 'api key configured',
		reachable: true,
		detail: 'api key configured',
		modelCount: 3,
		isDefault: false,
		cooldownUntil: null,
		lastCheckedAt: '2026-05-03T12:00:00Z',
		defaultForProfile: [],
		usage: { tokensUsedLastHour: 0, tokensUsedLast24h: 0, requestsLastHour: 0, requestsLast24h: 0 },
		quota: null,
		sparkline: []
	},
	{
		name: 'openrouter',
		kind: 'ENDPOINT',
		providerType: 'openai-compat',
		baseURL: 'https://openrouter.ai/api/v1',
		model: '',
		status: 'connected (200 models)',
		reachable: true,
		detail: 'connected',
		modelCount: 200,
		isDefault: false,
		cooldownUntil: null,
		lastCheckedAt: '2026-05-03T12:00:00Z',
		defaultForProfile: [],
		usage: { tokensUsedLastHour: 0, tokensUsedLast24h: 0, requestsLastHour: 0, requestsLast24h: 0 },
		quota: null,
		sparkline: []
	},
	{
		name: 'lmstudio @vidar',
		kind: 'ENDPOINT',
		providerType: 'openai-compat',
		baseURL: 'http://vidar.local:1234/v1',
		model: '',
		status: 'connected (3 models)',
		reachable: true,
		detail: 'connected',
		modelCount: 3,
		isDefault: false,
		cooldownUntil: null,
		lastCheckedAt: '2026-05-03T12:00:00Z',
